&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;u&gt;वायुवेगमापी&lt;/u&gt;&lt;/strong&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; एक उपकरण है जिसका उपयोग हवा के बल और वेग&lt;/font&gt;&lt;/font&gt;&lt;/span&gt;&lt;/u&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; को मापने के लिए किया जाता है&lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;यह एक सामान्य मौसम स्टेशन उपकरण भी है। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;इसका आविष्कार&amp;nbsp;&lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;15वीं शताब्दी में&amp;nbsp;&lt;/font&gt;&lt;/font&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;लियोन बतिस्ता अल्बर्टी &lt;/font&gt;&lt;/font&gt;&lt;/span&gt;ने किया&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; &lt;/font&gt;&lt;/font&gt;&lt;/span&gt;था।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;आर्द्रतामापी&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; एक उपकरण है जिसका उपयोग सापेक्ष आर्द्रता को मापने के लिए किया जाता है। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;आर्द्रता हवा में नमी की मात्रा का माप है। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;साइक्रोमीटर एक &lt;/font&gt;&lt;/font&gt;आर्द्रतामापी&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; का एक उदाहरण है।&lt;/font&gt;&lt;/font&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;तुंगतामापी&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; एक &lt;/font&gt;&lt;/font&gt;निर्द्रव वायुदाबमापी&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; है जो परिवेशी वायु के निरपेक्ष दाब&amp;nbsp;को मापता है और इसे मानक &lt;/font&gt;&lt;/font&gt;&lt;span style=&quot;&quot;&gt;दाब&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;-ऊंचाई संबंध के अनुसार समुद्र तल से ऊंचाई के रूप में प्रदर्शित करता है। &lt;/font&gt;&lt;/font&gt;तुंगतामापी&amp;nbsp;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;एक अत्यधिक परिष्कृत &lt;/font&gt;&lt;/font&gt;निर्द्रव वायुदाबमापी&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; है क्योंकि यह एक खाली कैप्सूल का उपयोग करता है जिसकी&amp;nbsp;गति या बल सीधे कैप्सूल के बाहर दबाव से संबंधित होता है।&lt;/font&gt;&lt;/font&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;धारामापी (गैल्वेनोमीटर&lt;/strong&gt;&lt;strong&gt;)&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; एक &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;उपकरण है जिसका उपयोग &lt;/font&gt;&lt;/font&gt;&lt;span style=&quot;&quot;&gt;विद्युत धारा का मापन&amp;nbsp;&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;के लिए किया जाता है&lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;। &lt;/font&gt;&lt;/font&gt;धारामापी&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; विद्युत ऊर्जा को यांत्रिक ऊर्जा में बदलने के सिद्धांत पर कार्य करता है। &lt;/font&gt;&lt;/font&gt;धारामापी&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; धारा की दिशा और परिमाण दोनों को दर्शाता है।&lt;/font&gt;&lt;/font&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;दुग्धमापी (लैक्टोमीटर)&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; एक उपकरण है जिसका उपयोग दूध के घनत्व&lt;/font&gt;&lt;/font&gt;&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; को मापने के लिए किया जाता है,&amp;nbsp;&lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;या आम आदमी के शब्दों में, यह दूध की शुद्धता की जांच करने के लिए उपयोग किया जाने वाला उपकरण है। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;जितना अधिक घनत्व होगा, दूध उतना ही शुद्ध होगा। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;इसका आविष्कार&amp;nbsp;&lt;/font&gt;&lt;/font&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;डिकास &lt;/font&gt;&lt;/font&gt;&lt;/span&gt;ने किया था।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वायुदाबमापी&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&amp;nbsp;एक उपकरण है जिसका उपयोग वायुमंडलीय &lt;/font&gt;&lt;/font&gt;दाब&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; को मापने के लिए किया जाता&amp;nbsp;है&lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;यह मौसम बदलाव की भविष्यवाणी करने में भी मदद कर सकता&amp;nbsp;है। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;इसका आविष्कार&amp;nbsp;&lt;/font&gt;&lt;/font&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;इवेंजेलिस्टा टोरिसेली &lt;/font&gt;&lt;/font&gt;&lt;/span&gt;ने किया था।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मील-मापी&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; वाहन के पहियों से जुड़ा एक उपकरण है जिसका उपयोग&amp;nbsp;वाहन द्वारा तय की गई &lt;/font&gt;&lt;/font&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;दूरी को मापने के&lt;/font&gt;&lt;/font&gt;&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; लिए किया जाता&amp;nbsp;है। &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;इसका आविष्कार&amp;nbsp;&lt;/font&gt;&lt;/font&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;थॉमस सेवरी&amp;nbsp;&lt;/font&gt;&lt;/font&gt;&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;ने जहाजों के लिए किया था।&lt;/font&gt;&lt;/font&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:330px;&quot;&gt;
	&lt;caption&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font color=&quot;#58595b&quot; style=&quot;vertical-align: inherit;&quot;&gt;उपकरण और उनके उपयोग&lt;/font&gt;&lt;/font&gt;&lt;/li&gt;
	&lt;/ul&gt;
