			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit; font-weight: 400;&quot;&gt;उपयोग&lt;/font&gt;&lt;/font&gt;&lt;/th&gt;
