		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;वायुदाबमापी&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;वायुमंडलीय दाब को मापना&lt;/font&gt;&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;द्रवघनत्वमापी (हाइड्रोमीटर)&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;द्रवों के घनत्व को मापना&lt;/font&gt;&lt;/font&gt;&lt;/td&gt;
