		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;आर्द्रतामापी (हाइग्रोमीटर)&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;वातावरण में आर्द्रता को मापना&lt;/font&gt;&lt;/font&gt;&lt;/td&gt;
