			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;दूध की शुद्धता को मापना&lt;/font&gt;&lt;/font&gt;&lt;/td&gt;
